# METHODES

def count_handles(array)
  puts "Il y a #{array.length} handles dans la liste."
end

def shortest_handle(array)
  shortest = array.min_by { |h| h[1..-1].length }
  puts "Le handle le plus court est : #{shortest}"
end

def five_char_handles(array)
  count = array.count { |h| h[1..-1].length == 5 }
  puts "Il y a #{count} handles de 5 caractères."
end

def uppercase_handles(array)
  count = array.count { |h| h[1] == h[1].upcase && h[1] =~ /[A-Z]/ }
  puts "Il y a #{count} handles qui commencent par une majuscule."
end

def sort_alphabetically(array)
  puts "Handles triés alphabétiquement :"
  puts array.sort
end

def sort_by_size(array)
  puts "Handles triés par taille :"
  puts array.sort_by { |h| h[1..-1].length }
end

def find_position(array, handle)
  position = array.index(handle)
  if position
    puts "#{handle} est en position #{position} dans la liste."
  else
    puts "#{handle} n'est pas dans la liste."
  end
end

def size_distribution(array)
  puts "Répartition des handles par taille :"
  distribution = Hash.new(0)
  array.each { |h| distribution[h[1..-1].length] += 1 }
  distribution.sort.each do |size, count|
    puts "  #{size} caractères : #{count} handles"
  end
end

